-- Migration: glossary terms to DB
-- ============================================================
-- Moves the glossary from lib/glossary.ts (static) into
-- public.glossary_terms so content can be edited without a code
-- deploy. Seeds the table with 200+ existing + new terms across
-- SMSF, Mining, Foreign Investment, Super, Tax, Property, Crypto,
-- CFD, Regulatory, and General Finance categories.
-- ============================================================

CREATE TABLE IF NOT EXISTS public.glossary_terms (
  id          SERIAL PRIMARY KEY,
  slug        TEXT NOT NULL UNIQUE,
  term        TEXT NOT NULL,
  definition  TEXT NOT NULL,
  category    TEXT,
  sort_order  INTEGER DEFAULT 0,
  status      TEXT NOT NULL DEFAULT 'published',
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_glossary_terms_category
  ON public.glossary_terms (category) WHERE status = 'published';
CREATE INDEX IF NOT EXISTS idx_glossary_terms_term_lower
  ON public.glossary_terms ((LOWER(term))) WHERE status = 'published';

ALTER TABLE public.glossary_terms ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "public read published glossary" ON public.glossary_terms;
CREATE POLICY "public read published glossary" ON public.glossary_terms
  FOR SELECT USING (status = 'published');

-- Seed data — ON CONFLICT skips rows already present so re-running
-- this migration is idempotent.

ON CONFLICT (slug) DO NOTHING;

ON CONFLICT (slug) DO NOTHING;

ON CONFLICT (slug) DO NOTHING;

ON CONFLICT (slug) DO NOTHING;

ON CONFLICT (slug) DO NOTHING;
